sql:
SELECT component_id 
FROM components 
WHERE unit_price = (SELECT MAX(unit_price) FROM components);

SELECT DISTINCT c.component_id, c.designator, c.description, c.manufacturer, cl.quantity
FROM components c
JOIN component_locations cl ON c.component_id = cl.component_id;

SELECT component_id, SUM(quantity_used) AS total_quantity_used
FROM bill_of_materials
GROUP BY component_id;

SELECT components.component_id, components.designator, manufacturers.contact_email
FROM components
JOIN manufacturers ON components.manufacturer = manufacturers.manufacturer_name;
